import{_ as e,o as a,c as r,a4 as i}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Asterism (Star Effect)","description":"","frontmatter":{"title":"Asterism (Star Effect)","phenomenon":"asterism"},"headers":[],"relativePath":"optical-phenomena/asterism.md","filePath":"optical-phenomena/asterism.md","lastUpdated":1784177547000}'),s={name:"optical-phenomena/asterism.md"};function d(o,t,n,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="asterism-star-effect" tabindex="-1">Asterism (Star Effect) <a class="header-anchor" href="#asterism-star-effect" aria-label="Permalink to &quot;Asterism (Star Effect)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>When a gem contains needle- or tube-shaped inclusions aligned along specific crystallographic directions, light reflecting from these structures forms a 4-rayed or 6-rayed star on a cabochon cut. The classic example is 6-rayed star ruby/sapphire (corundum family); diopside can show a 4-rayed star. Asterism is most visible under a single point light source; diffuse light blurs the effect.</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Inclusion reflection: rutile (TiO₂) needles intersect at 60° / 120° angles aligned with the trigonal corundum c-axis. The cabochon&#39;s domed shape guides reflections outward, optically combining into six rays meeting at the apex.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Rays</th><th>Host</th><th>Needles</th></tr></thead><tbody><tr><td>Star Ruby / 星光红宝</td><td>6</td><td>Corundum</td><td>rutile (TiO₂)</td></tr><tr><td>Star Sapphire / 星光蓝宝</td><td>6</td><td>Corundum</td><td>rutile (TiO₂)</td></tr><tr><td>Star Diopside / 星光透辉石</td><td>4</td><td>Diopside</td><td>magnetite</td></tr><tr><td>Star Rose Quartz / 星光芙蓉石</td><td>6</td><td>Quartz</td><td>rutile</td></tr><tr><td>Star Garnet / 星光石榴石</td><td>4</td><td>Garnet</td><td>rutile / apatite</td></tr></tbody></table><p><em>See the <a href="./intro.html">optical phenomena overview</a>.</em></p>',8)])])}const u=e(s,[["render",d]]);export{p as __pageData,u as default};
